      outline: 2px solid $color-accent;
      outline-offset: 2px;
      border-radius: $radius-sm;
    }
  }

  &__label {
    white-space: nowrap;
  }

  &__shortcut {
    display: inline-flex;
    align-items: center;
    gap: $space-half;
  }
